#!/usr/bin/env bash
# Regenerate wifi-ap.env from appliance.env — per-unit SSID/PSK (build-instructions §8).
set -euo pipefail

APPLIANCE=/etc/sportassist/appliance.env
OUT=/etc/sportassist/wifi-ap.env

if [[ ! -f "$APPLIANCE" ]]; then
  echo "Missing $APPLIANCE — copy config/appliance-{serial}.env to the Pi first" >&2
  exit 2
fi

# shellcheck disable=SC1090
source "$APPLIANCE"

: "${APPLIANCE_SERIAL:?APPLIANCE_SERIAL required in appliance.env}"
: "${AP_PSK:?AP_PSK required in appliance.env}"
: "${AP_COUNTRY_CODE:=GB}"

cat >"$OUT" <<EOF
# Generated by ldrs-merge-appliance-env.sh — do not edit; change appliance.env instead.
APPLIANCE_SERIAL=${APPLIANCE_SERIAL}
AP_SSID=sport-assist-${APPLIANCE_SERIAL}
AP_PSK=${AP_PSK}
# AP_INTERFACE — optional; leave unset to auto-select Pi built-in Wi‑Fi (brcmfmac)
AP_COUNTRY_CODE=${AP_COUNTRY_CODE}
AP_CHANNEL=6
AP_ADDRESS=192.168.4.1
AP_NETMASK=255.255.255.0
AP_DHCP_RANGE_START=192.168.4.100
AP_DHCP_RANGE_END=192.168.4.150
AP_DHCP_LEASE_TIME=24h
EOF

chown root:sportassist "$OUT"
chmod 640 "$OUT"

echo "wifi-ap.env: AP_SSID=sport-assist-${APPLIANCE_SERIAL}"
